import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./AddEmployee.css";

function AddEmployee() {
  const navigate = useNavigate();
  const { id } = useParams();

  const [activeTab, setActiveTab] = useState("personal");

  const [employee, setEmployee] = useState({
    firstName: "",
    lastName: "",
    empId: "",
    email: "",
    dob: "",
    age: "",
    phone: "",
    gender: "",
    maritalStatus: "",

    designation: "",
    salary: "",
    department: "",
    role: "Employee",
    skills: "",
    otherSkill: "",

    bankHolderName: "",
    bankName: "",
    accountNumber: "",
    ifsc: "",

    qualification: "",
    university: "",
    passingYear: "",
  });

  const [errors, setErrors] = useState({
    email: "",
    phone: "",
    ifsc: "",
    name: "",
    salary: "",
    year: ""
  });

  useEffect(() => {
    if (!id) return;

    const employees = JSON.parse(localStorage.getItem("employees")) || [];
    const found = employees.find((emp) => emp.id === id);
    if (found) setEmployee(found);
  }, [id]);


  // ---------- VALIDATION HELPERS ----------
  const validateEmail = (email) =>
    /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const validatePhone = (phone) =>
    /^[0-9]{10}$/.test(phone);

  const validateIFSC = (code) =>
    /^[A-Z]{4}0[A-Z0-9]{6}$/.test(code.toUpperCase());

  const validateName = (name) =>
    /^[A-Za-z]{2,}$/.test(name);

  const validateSalary = (salary) =>
    /^[0-9]+$/.test(salary) && Number(salary) > 0;

  const validatePassingYear = (year) => {
    const current = new Date().getFullYear();
    return /^[0-9]{4}$/.test(year) && year >= 1900 && year <= current;
  };


  // ---------- HANDLE INPUT ----------
  const handleChange = (e) => {
    const { name, value } = e.target;

    if (name === "dob") {
      const birthYear = new Date(value).getFullYear();
      const currentYear = new Date().getFullYear();
      setEmployee({ ...employee, dob: value, age: currentYear - birthYear });
      return;
    }

    setEmployee({ ...employee, [name]: value });

    if (name === "email")
      setErrors({ ...errors, email: validateEmail(value) ? "" : "Invalid Email" });

    if (name === "phone")
      setErrors({ ...errors, phone: validatePhone(value) ? "" : "Phone must be 10 digits" });

    if (name === "ifsc")
      setErrors({
        ...errors,
        ifsc: validateIFSC(value)
          ? ""
          : "Invalid IFSC (Ex: SBIN0001234)",
      });

    if (name === "firstName" || name === "lastName")
      setErrors({
        ...errors,
        name: validateName(value)
          ? ""
          : "Name must contain alphabets only (min 2 letters)",
      });

    if (name === "salary")
      setErrors({
        ...errors,
        salary: validateSalary(value) ? "" : "Enter valid salary",
      });

    if (name === "passingYear")
      setErrors({
        ...errors,
        year: validatePassingYear(value)
          ? ""
          : "Enter valid year (1900 - Current Year)",
      });
  };


  // ---------- SUBMIT ----------
  const handleSubmit = (e) => {
    e.preventDefault();

    const required = [
      "firstName", "lastName", "empId", "email",
      "dob", "phone", "gender", "maritalStatus",
      "designation", "salary", "department"
    ];

    for (let f of required) {
      if (!employee[f]) {
        alert("Please fill all required fields");
        return;
      }
    }

    if (!validateName(employee.firstName) || !validateName(employee.lastName)) {
      alert("First & Last Name must contain alphabets only");
      return;
    }

    if (!validateEmail(employee.email)) {
      alert("Invalid Email");
      return;
    }

    if (!validatePhone(employee.phone)) {
      alert("Phone must be 10 digits");
      return;
    }

    if (!validateIFSC(employee.ifsc)) {
      alert("Invalid IFSC Code");
      return;
    }

    if (!validateSalary(employee.salary)) {
      alert("Enter valid salary");
      return;
    }

    if (employee.passingYear && !validatePassingYear(employee.passingYear)) {
      alert("Invalid Passing Year");
      return;
    }

    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    if (id) {
      employees = employees.map((emp) =>
        emp.id === id ? { ...employee } : emp
      );
      alert("Employee Updated Successfully!");
    } else {
      employees.push({ ...employee, id: Date.now().toString() });
      alert("Employee Added Successfully!");
    }

    localStorage.setItem("employees", JSON.stringify(employees));
    navigate("/dashboard/employee-details");
  };


  // ---------- UI ----------
  return (
    <div className="add-employee-page">
      <h2>{id ? "Edit Employee" : "Add Employee"}</h2>

      <form className="employee-form" onSubmit={handleSubmit}>

        {/* ---------- TABS ---------- */}
        <div className="tabs">
          <button type="button"
            className={activeTab === "personal" ? "tab active" : "tab"}
            onClick={() => setActiveTab("personal")}
          >
            PERSONAL
          </button>

          <button type="button"
            className={activeTab === "employment" ? "tab active" : "tab"}
            onClick={() => setActiveTab("employment")}
          >
            EMPLOYMENT
          </button>

          <button type="button"
            className={activeTab === "bank" ? "tab active" : "tab"}
            onClick={() => setActiveTab("bank")}
          >
            BANK
          </button>

          <button type="button"
            className={activeTab === "education" ? "tab active" : "tab"}
            onClick={() => setActiveTab("education")}
          >
            EDUCATION
          </button>
        </div>


        {/* ---------- PERSONAL ---------- */}
        {activeTab === "personal" && (
          <>
            <h3>Personal Details</h3>

            <div className="employee-grid">

              <input name="firstName" placeholder="First Name"
                value={employee.firstName} onChange={handleChange} />

              <input name="lastName" placeholder="Last Name"
                value={employee.lastName} onChange={handleChange} />

              <input name="empId" placeholder="Employee ID"
                value={employee.empId} onChange={handleChange} />

              <input name="email" placeholder="Email"
                value={employee.email} onChange={handleChange} />
              {errors.email && <span className="error-text">{errors.email}</span>}

              <input type="date" name="dob"
                value={employee.dob} onChange={handleChange} />

              <select
                       name="age"
                         value={employee.age}
                     onChange={handleChange}
>
                      <option value="">Select Age</option>
                     {[...Array(60)].map((_, i) => {
                           const age = i + 18;
                           return <option key={age} value={age}>{age}</option>;
                        })}
                           </select>


              <input name="phone" placeholder="Phone Number"
                value={employee.phone} onChange={handleChange} />
              {errors.phone && <span className="error-text">{errors.phone}</span>}

              <select name="gender"
                value={employee.gender} onChange={handleChange}>
                <option value="">Select Gender</option>
                <option>Male</option>
                <option>Female</option>
              </select>

              <select name="maritalStatus"
                value={employee.maritalStatus} onChange={handleChange}>
                <option value="">Select Marital Status</option>
                <option>Single</option>
                <option>Married</option>
              </select>

            </div>
          </>
        )}


        {/* ---------- EMPLOYMENT ---------- */}
        {activeTab === "employment" && (
          <>
            <h3>Job Details</h3>

            <div className="employee-grid">
              <input name="designation" placeholder="Designation"
                value={employee.designation} onChange={handleChange} />

              <input name="salary" placeholder="Salary"
                value={employee.salary} onChange={handleChange} />
              {errors.salary && <span className="error-text">{errors.salary}</span>}

              <select name="department"
                value={employee.department} onChange={handleChange}>
                <option value="">Select Department</option>
                <option>Frontend</option>
                <option>Backend</option>
                <option>Web Developer</option>
                <option>Quality Check (QC)</option>
                <option>Database</option>
                <option>IT</option>
                <option>Digital Marketing</option>
                <option>HR</option>
                <option>Sales</option>
                <option>USIT Recruiters</option>
                <option>Business Developer</option>
              </select>

              <select name="skills"
                value={employee.skills} onChange={handleChange}>
                <option value="">Select Skill</option>
                <option>Java</option>
                <option>Advanced Java</option>
                <option>Python</option>
                <option>NodeJS</option>
                <option>React</option>
                <option>Angular</option>
                <option>MongoDB</option>
                <option>Other</option>
              </select>

              {employee.skills === "Other" && (
                <input
                  name="otherSkill"
                  placeholder="Enter Skill"
                  value={employee.otherSkill}
                  onChange={handleChange}
                />
              )}

              <select name="role"
                value={employee.role} onChange={handleChange}>
                <option>Employee</option>
                <option>Admin</option>
              </select>
            </div>
          </>
        )}


        {/* ---------- BANK ---------- */}
        {activeTab === "bank" && (
          <>
            <h3>Bank Details</h3>

            <div className="employee-grid">

              <input name="bankHolderName" placeholder="Account Holder Name"
                value={employee.bankHolderName} onChange={handleChange} />

              <input name="bankName" placeholder="Bank Name"
                value={employee.bankName} onChange={handleChange} />

              <input name="accountNumber" placeholder="Account Number"
                value={employee.accountNumber} onChange={handleChange} />

              <input name="ifsc" placeholder="IFSC Code"
                value={employee.ifsc} onChange={handleChange} />
              {errors.ifsc && <span className="error-text">{errors.ifsc}</span>}

            </div>
          </>
        )}


        {/* ---------- EDUCATION ---------- */}
        {activeTab === "education" && (
          <>
            <h3>Educational Details</h3>

            <div className="employee-grid">

              <input name="qualification" placeholder="Highest Qualification"
                value={employee.qualification} onChange={handleChange} />

              <input name="university" placeholder="University"
                value={employee.university} onChange={handleChange} />

              <input name="passingYear" placeholder="Passing Year"
                value={employee.passingYear} onChange={handleChange} />
              {errors.year && <span className="error-text">{errors.year}</span>}
            </div>

            <button type="submit" className="save-btn">
              {id ? "Update Employee" : "Save Employee"}
            </button>
          </>
        )}

      </form>
    </div>
  );
}

export default AddEmployee;
